const SIX_H = 6*60*60*1000;
const out = [];
for (const item of $input.all()) {
  const a = item.json;
  if (!a.dest_chat) continue;
  if (a.last_triggered_at) {
    const last = new Date(a.last_triggered_at).getTime();
    if (Date.now() - last < SIX_H) continue;
  }
  const sym = String(a.symbol).replace('USDT','').toUpperCase();
  let current = null; let label = '';
  try {
    if (a.kind === 'price') {
      const r = await this.helpers.httpRequest({ url: `https://api.binance.com/api/v3/ticker/price?symbol=${sym}USDT`, json: true });
      current = parseFloat(r.price);
      label = `preço ${current}`;
    } else {
      const cb = await this.helpers.httpRequest({ url: `https://api.exchange.coinbase.com/products/${sym}-USD/ticker`, json: true, headers: { 'User-Agent': 'neovertex' } });
      const bn = await this.helpers.httpRequest({ url: `https://api.binance.com/api/v3/ticker/price?symbol=${sym}USDT`, json: true });
      const c = parseFloat(cb.price); const b = parseFloat(bn.price);
      current = b ? ((c - b) / b * 100) : 0;
      label = `prêmio Coinbase ${current.toFixed(3)}%`;
    }
  } catch (e) { continue; }
  const t = parseFloat(a.target_value);
  const met = (a.operator === 'gte') ? (current >= t) : (current <= t);
  if (!met) continue;
  const op = a.operator === 'gte' ? '>=' : '<=';
  const tipo = a.kind === 'price' ? 'Alerta de preço' : 'Alerta institucional';
  out.push({ json: { alert_id: a.id, symbol: sym, dest_chat: a.dest_chat,
    message: `${tipo} ${sym}: ${label} atingiu o alvo (${op} ${t}).` } });
}
return out;
